var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"쭉 좋아했습니다.","JPN":"ずっと好きでした。","ENG":"I've always liked you.","TWN":"我一直喜歡你。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"제 마음을...... 받아 주세요.","JPN":"私の気持ちを……受け取ってください。","ENG":"Please accept... my heart.","TWN":"這是我的一點心意……請收下吧。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"이건...... 초콜릿?","JPN":"これは……チョコレート？","ENG":"This is... Chocolate?","TWN":"這是……巧克力？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"네! 발렌타인은 이렇게 사랑을 고백하는 날이잖아요?","JPN":"はい！\\nバレンタインデーは、こうして愛を告白する日でしょう？","ENG":"Yes! Valentine's Day is the day you show your love with chocolate, right?","TWN":"嗯！情人節是告白的節日嘛。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"받아 주실 거죠?","JPN":"受け取ってくれますよね？","ENG":"I hope you accept it.","TWN":"你會收下吧？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"......마음은 알겠지만, 미안.","JPN":"……気持ちはわかったけど、ごめん。","ENG":"I appreciate the thought, but I'm sorry.","TWN":"……我收到妳的心意了。但……抱歉。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"난 이런 상업성 짙은 행사는 질색이라서.","JPN":"僕はこういう商業的なお祭り騒ぎは嫌いなんだ。","ENG":"I really don't like these sort of corporate schemes.","TWN":"我可不喜歡商業性這麼濃的活動。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그 날, 나는 사랑을 잃었다.","JPN":"あの日、私は愛を失った。","ENG":"That day, I lost my love.","TWN":"那天，我失戀了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"발렌타인의 초콜릿이라면 불가능한 사랑도 마법처럼 이뤄질 거란 착각에 빠졌던 것이다.","JPN":"バレンタインチョコなら、\\n不可能な恋も魔法のように叶うと勘違いしていたのだ。","ENG":"I was delusional to think that Valentine's Day chocolate would magically make my love come true.","TWN":"那時我陷入了一種錯覺，誤以為情人節的巧克力像魔法一樣，能實現不可能的愛戀。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만...... 초콜릿 따위가 그런 마법 같은 사랑을 이뤄 줄 리 없었다.","JPN":"だが……たかがチョコレートが、恋を叶えてくれるはずはない。","ENG":"But there was no magic in the chocolate.","TWN":"但是……巧克力而已，沒有讓我得到愛情的魔力。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"큭큭...... 그래, 초콜릿은 아무 것도 아니야.","JPN":"ククッ……そう、チョコレートには何の力もないの。","ENG":"Hah hah. No. Chocolate is nothing.","TWN":"哈哈哈……是啊，巧克力算什麼呢。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"초콜릿의 달콤함은 아무 것도 바꾸지 못해.","JPN":"チョコレートの甘さは何一つ変えることができないわ。","ENG":"The sweetness of chocolate can't change anything.","TWN":"甜甜蜜蜜的巧克力什麼都改變不了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 난 할 수 있어. 모든 걸 바꿀 수 있지.","JPN":"でも、私はできる。すべてを変えることができるの。","ENG":"But I can. I can change everything.","TWN":"但我可以啊，我可以改變一切。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 되게 만들 거야.","JPN":"だから、変えてやるわ。","ENG":"I will change everything.","TWN":"我會去改變一切的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니 모두 기대해.","JPN":"みんな、見てなさい。","ENG":"You all just watch.","TWN":"所以你們都等好了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>10년 뒤</color>      \\n관리국 산하, CS 미래식량개발연구부      ","JPN":"<color=#ffd34c>10年後</color>      \\n管理局傘下、CS未来食糧開発研究部      ","ENG":"[[","TWN":"<color=#ffd34c>10年後</color>      \\n管理局, CS 未來糧食研究部","THA":"<color=#ffd34c>10 ปีผ่านไป</color>      \\nหน่วยงานในสังกัดขององค์การบริหารโลก แผนกวิจัยและพัฒนาอาหารแห่งอนาคตจากเคาน์เตอร์ไซด์      ","VTN":"<color=#ffd34c>10 năm sau</color>      \\nHội viên Cục Quản Lý, Phòng Nghiên Cứu và Phát triển Thực Phẩm Tương Lai CS","SCN":"<color=#ffd34c>10年后</color>      \\n管理局, CS 未来食品研究部      ","DEU":"<color=#ffd34c>10\xA0Jahre später</color>      \\nForschungs- und Entwicklungsabteilung von CS\xA0Future Food (verbunden mit der Administration)      ","FRA":"<color=#ffd34c>10\xA0ans plus tard</color>      \\nDépartement de recherche et développement affilié à l'Administration\xA0: Future\xA0Food\xA0CS      "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"자, 이번 주도 고생 많으셨습니다.","JPN":"では、今週もお疲れ様でした。","ENG":"Alright everyone, good work this week.","TWN":"各位這周辛苦了。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"저희 프로젝트의 결과물이 국민의 식탁에 오를 일도 이제 머지 않았군요.","JPN":"私たちのプロジェクトの成果が、国民の食卓にのぼる日も遠くないですね。","ENG":"It won't be long before the fruits of our labor will be on our citizen's tables.","TWN":"我們這次專案的成果很快就要對外公佈了。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};